import{_ as l,o as i,c as a,ae as o}from"./chunks/framework.B9bl8Hm5.js";const S=JSON.parse('{"title":"CSS 知识点","description":"","frontmatter":{},"headers":[],"relativePath":"css.md","filePath":"css.md"}'),d={name:"css.md"};function c(t,e,r,s,n,h){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="css-知识点" tabindex="-1">CSS 知识点 <a class="header-anchor" href="#css-知识点" aria-label="Permalink to &quot;CSS 知识点&quot;">​</a></h1><h2 id="_1-css-选择器优先级" tabindex="-1">1. CSS 选择器优先级 <a class="header-anchor" href="#_1-css-选择器优先级" aria-label="Permalink to &quot;1. CSS 选择器优先级&quot;">​</a></h2><ul><li>内联样式 &gt; ID选择器 &gt; 类选择器 &gt; 标签选择器 &gt; 通配符选择器</li><li>计算规则：内联样式(1000)，ID选择器(100)，类选择器(10)，标签选择器(1)</li></ul><h2 id="_2-css-盒模型" tabindex="-1">2. CSS 盒模型 <a class="header-anchor" href="#_2-css-盒模型" aria-label="Permalink to &quot;2. CSS 盒模型&quot;">​</a></h2><ul><li>标准盒模型：内容(content) + 内边距(padding) + 边框(border) + 外边距(margin)</li><li>IE盒模型：内容(content)包含内边距和边框</li><li>通过 <code>box-sizing</code> 属性切换：<code>content-box</code>(标准)，<code>border-box</code>(IE)</li></ul><h2 id="_3-css-定位" tabindex="-1">3. CSS 定位 <a class="header-anchor" href="#_3-css-定位" aria-label="Permalink to &quot;3. CSS 定位&quot;">​</a></h2><ul><li><code>static</code>：默认定位，遵循文档流</li><li><code>relative</code>：相对定位，相对于自身原位置偏移</li><li><code>absolute</code>：绝对定位，相对于最近的非static父元素定位</li><li><code>fixed</code>：固定定位，相对于视口定位</li><li><code>sticky</code>：粘性定位，结合了relative和fixed的特点</li></ul><h2 id="_4-flexbox-布局" tabindex="-1">4. Flexbox 布局 <a class="header-anchor" href="#_4-flexbox-布局" aria-label="Permalink to &quot;4. Flexbox 布局&quot;">​</a></h2><ul><li>一维布局模型，通过 <code>display: flex</code> 启用</li><li>主要属性： <ul><li><code>flex-direction</code>：主轴方向</li><li><code>justify-content</code>：主轴对齐方式</li><li><code>align-items</code>：交叉轴对齐方式</li><li><code>flex-wrap</code>：是否换行</li><li><code>flex</code>：子项的伸缩比例</li></ul></li></ul><h2 id="_5-grid-布局" tabindex="-1">5. Grid 布局 <a class="header-anchor" href="#_5-grid-布局" aria-label="Permalink to &quot;5. Grid 布局&quot;">​</a></h2><ul><li>二维布局模型，通过 <code>display: grid</code> 启用</li><li>主要属性： <ul><li><code>grid-template-columns</code>：列定义</li><li><code>grid-template-rows</code>：行定义</li><li><code>grid-gap</code>：网格间距</li><li><code>grid-area</code>：网格区域</li></ul></li></ul><h2 id="_6-css-预处理器" tabindex="-1">6. CSS 预处理器 <a class="header-anchor" href="#_6-css-预处理器" aria-label="Permalink to &quot;6. CSS 预处理器&quot;">​</a></h2><ul><li>Sass/SCSS：变量、嵌套、混合、继承等特性</li><li>Less：类似Sass的功能</li><li>Stylus：更灵活的语法</li></ul><h2 id="_7-css-动画" tabindex="-1">7. CSS 动画 <a class="header-anchor" href="#_7-css-动画" aria-label="Permalink to &quot;7. CSS 动画&quot;">​</a></h2><ul><li><code>transition</code>：过渡效果</li><li><code>animation</code>：关键帧动画</li><li><code>transform</code>：变换（旋转、缩放、平移等）</li></ul><h2 id="_8-响应式设计" tabindex="-1">8. 响应式设计 <a class="header-anchor" href="#_8-响应式设计" aria-label="Permalink to &quot;8. 响应式设计&quot;">​</a></h2><ul><li>媒体查询：<code>@media</code> 规则</li><li>弹性布局：Flexbox 和 Grid</li><li>相对单位：<code>rem</code>, <code>em</code>, <code>vw</code>, <code>vh</code> 等</li></ul><h2 id="_9-css-性能优化" tabindex="-1">9. CSS 性能优化 <a class="header-anchor" href="#_9-css-性能优化" aria-label="Permalink to &quot;9. CSS 性能优化&quot;">​</a></h2><ul><li>减少重排(reflow)和重绘(repaint)</li><li>使用 CSS 精灵图</li><li>避免使用 <code>!important</code></li><li>减少选择器的复杂度</li><li>使用 CSS 变量提高可维护性</li></ul>',19)])])}const _=l(d,[["render",c]]);export{S as __pageData,_ as default};
